import java.io.IOException;
import java.io.PrintWriter;
import org.apache.commons.text.StringEscapeUtils;

public class XssFixedCode {

    public static void main(String[] args) throws IOException {
        // Simulating user input coming from an untrusted source
        String userInput = "<script>alert('XSS attack!')</script>";

        // Encode user input to prevent XSS attacks
        String encodedUserInput = StringEscapeUtils.escapeHtml4(userInput);

        // Properly handling user input by encoding it before outputting it to a web page
        try (PrintWriter out = new PrintWriter("output.html", "UTF-8")) {
            out.println("<html>");
            out.println("<body>");
            out.println("<p>User input: " + encodedUserInput + "</p>");
            out.println("</body>");
            out.println("</html>");
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
